bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

using benchmark_clock = std::chrono::steady_clock;

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
__global__ void bench_kernel_float(const float* data, size_t len, size_t chunk_size, float* partial_sums) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  size_t total_chunks = (len + chunk_size - 1) / chunk_size;
  if (idx < total_chunks) {
    size_t base = idx * chunk_size;
    size_t size = chunk_size;
    if (base + size > len) size = len - base;
    float sum = 0;
#ifdef BASELINE_IMPL
    float f = data[0];
    for (size_t i = 0; i < size; i++) {
      float t = data[base + i];
      for (unsigned int j = 0; j < compute_iterations; j++) {
        t = t * t + f;
      }
      sum += t;
