template <typename Element, unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, static_cast<int>(compute_iterations)};

  constexpr size_t static_chunk_size = 4096;
  const size_t len = cs.element_count<Element>();

  Element* h_data = new Element[len];
  for (size_t i = 0; i < len; i++) h_data[i] = 0;

  Element* d_data;
  cudaMalloc(&d_data, len * sizeof(Element));
  cudaMemcpy(d_data, h_data, len * sizeof(Element), cudaMemcpyHostToDevice);

  const size_t total_chunks = (len + static_chunk_size - 1) / static_chunk_size;
  const int threads_per_block = 256;
  const int blocks = (total_chunks + threads_per_block - 1) / threads_per_block;

  Element* d_partial_sums;
  cudaMalloc(&d_partial_sums, blocks * sizeof(Element));
  cudaMemset(d_partial_sums, 0, blocks * sizeof(Element));

  cudaEvent_t start, stop;
  cudaEventCreate(&start);
  cudaEventCreate(&stop);
  cudaEventRecord(start);

  if constexpr (std::is_same<Element, float>::value) {
    bench_kernel_float<compute_iterations><<<blocks, threads_per_block>>>(d_data, len, static_chunk_size, d_partial_sums);
  } else if constexpr (std::is_same<Element, double>::value) {
    bench_kernel_double<compute_iterations><<<blocks, threads_per_block>>>(d_data, len, static_chunk_size, d_partial_sums);
  } else if constexpr (std::is_same<Element, int>::value) {
    bench_kernel_int<compute_iterations><<<blocks, threads_per_block>>>(d_data, len, static_chunk_size, d_partial_sums);
  }

  cudaEventRecord(stop);
  cudaEventSynchronize(stop);
  float milliseconds = 0;
  cudaEventElapsedTime(&milliseconds, start, stop);

  std::vector<Element> h_partial_sums(blocks);
  cudaMemcpy(h_partial_sums.data(), d_partial_sums, blocks * sizeof(Element), cudaMemcpyDeviceToHost);

  Element sum = 0;
  for (auto v : h_partial_sums) sum += v;

  h_data[0] = sum;

  const auto computations = cs.compute_ops<Element>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << milliseconds << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations) / milliseconds *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / milliseconds *
                   1000. / (1000. * 1000. * 1000.)
            << std::endl;

  delete[] h_data;
  cudaFree(d_data);
  cudaFree(d_partial_sums);
}

template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<float, compute_iterations>(cd, size);
  runbench<double, compute_iterations>(cd, size);
  runbench<int, compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

